mapper.select:
/** UsptExpertCrqfcDao.selectList */ select expert_crqfc_id /**전문가자격증ID**/ ,expert_id /**전문가ID**/ ,acqdt /**취득일**/ ,crqfc_nm /**자격증명**/ ,issu_instt_nm /**발급기관명**/ ,creator_id /**생성자ID(CMMT_MEMBER.MEMBER_ID)**/ ,created_dt /**생성일시**/ ,updater_id /**수정자ID(CMMT_MEMBER.MEMBER_ID)**/ ,updated_dt /**수정일시**/ from uspt_expert_crqfc where 1=1
and expert_acdmcr_id = #{expertAcdmcrId}
and expert_id = #{expertId}

mapper.insert:
/** UsptExpertCrqfcDao.insert */
insert into uspt_expert_crqfc (
	 expert_crqfc_id
	,expert_id
	,acqdt
	,crqfc_nm
	,issu_instt_nm
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{expertCrqfcId}
	,#{expertId}
	,#{acqdt}
	,#{crqfcNm}
	,#{issuInsttNm}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** UsptExpertCrqfcDao.update */
update uspt_expert_crqfc
     set acqdt                     = #{acqdt}
		, crqfc_nm                  = #{crqfcNm}
		, issu_instt_nm             = #{issuInsttNm}
		, updater_id                = #{updaterId}
		, updated_dt                = #{updatedDt}
where expert_crqfc_id = #{expertCrqfcId}
   and expert_id                 = #{expertId}

mapper.delete:
/** UsptExpertCrqfcDao.delete*/
delete from uspt_expert_crqfc
where expert_crqfc_id = #{expertCrqfcId}
   and expert_id                 = #{expertId}

/** UsptExpertCrqfcDao.deleteExpert*/
delete from uspt_expert_crqfc
where expert_id = #{expertId}
